import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterModule } from '@angular/router';
import { ButtonModule } from 'primeng/button';
import { ThemeComponent } from '../theme/theme.component';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';

@Component({
  selector: 'app-unauthorized',
  imports: [
    CommonModule,
    RouterModule,
    ButtonModule,
    ThemeComponent,
    TranslatePipe,
  ],
  templateUrl: './unauthorized.component.html',
  styleUrls: ['./unauthorized.component.scss'],
})
export class UnauthorizedComponent implements OnInit {
  private readonly route = inject(ActivatedRoute);
  private readonly translate = inject(TranslateService);

  requiredPermission: string | null = null;

  ngOnInit(): void {
    this.requiredPermission =
      this.route.snapshot.queryParamMap.get('reason') === 'no_permissions'
        ? this.translate.instant('SHARED.UNAUTHORIZED.NO_PERMISSIONS_ASSIGNED')
        : this.route.snapshot.queryParamMap.get('requiredPermission');
  }
}
